// ── Tome Chapter Database ──
// Real chapter/book titles and summaries for classical works.
// wordCount is a realistic per-chapter estimate; estimatedMinutes = wordCount / 200 rounded.

export interface TomeChapter {
  id: string               // "odyssey-ch-1"
  bookId: string           // "the-odyssey"
  number: number           // 1, 2, 3…
  title: string            // real chapter title (not "Chapter 1")
  wordCount: number        // realistic estimate
  estimatedMinutes: number // wordCount / 200 rounded
  summary: string          // 1 sentence capturing what happens
  quizAvailable: boolean
}

